INSERT INTO `timeline_entries` (`id`, `type`, `name`, `year_start`, `year_end`, `description`, `portrait_url`, `color`, `sort_order`, `created_at`, `updated_at`) VALUES (1,'physicist','Архимед',-287,-212,'Древнегреческий математик, физик и инженер из Сиракуз. Заложил основы статики и гидростатики, сформулировал закон Архимеда, ввёл понятие центра тяжести, развил методы вычисления площадей и объёмов, предвосхитившие интегральное исчисление.','https://upload.wikimedia.org/wikipedia/commons/thumb/e/e7/Domenico-Fetti_Archimedes_1620.jpg/500px-Domenico-Fetti_Archimedes_1620.jpg','#f59e0b',1,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(2,'physicist','Герон Александрийский',10,75,'Александрийский инженер, механик и математик. Автор труда «Пневматика», в котором описал множество механических устройств, включая паровой шар — эолипил, первый паровой двигатель в истории. Заложил основы пневматики и прикладной механики.','https://upload.wikimedia.org/wikipedia/commons/thumb/a/a0/Hero_of_Alexandria%2C_Belopoiika%2C_Paris%2C_Graec._2442.jpg/500px-Hero_of_Alexandria%2C_Belopoiika%2C_Paris%2C_Graec._2442.jpg','#f97316',2,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(3,'discovery','Эолипил — первый паровой двигатель',60,NULL,'Герон Александрийский описал «эолипил» — шар, вращающийся под действием пара, выходящего из сопел. Это первое в истории устройство, преобразовывающее тепловую энергию в механическое движение.','https://upload.wikimedia.org/wikipedia/commons/thumb/a/a5/Greek_title_of_Hero_of_Alexandria%2C_16th_century.png/500px-Greek_title_of_Hero_of_Alexandria%2C_16th_century.png','#f97316',3,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(4,'physicist','Клавдий Птолемей',100,170,'Александрийский астроном, математик и географ. Создал геоцентрическую систему мира, изложенную в «Альмагесте», которая доминировала в астрономии более тысячи лет. Развил тригонометрию и оптику, изучал преломление света.','https://upload.wikimedia.org/wikipedia/commons/thumb/c/c9/Ptolemy_1476_with_armillary_sphere_model.jpg/500px-Ptolemy_1476_with_armillary_sphere_model.jpg','#8b5cf6',4,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(5,'discovery','Геоцентрическая система мира',150,NULL,'В «Альмагесте» Птолемей обосновал геоцентрическую модель Вселенной: Земля находится в центре, а Солнце, Луна и планеты движутся по сложным орбитам — эпициклам и деферентам.','https://upload.wikimedia.org/wikipedia/commons/thumb/c/c9/Ptolemy_1476_with_armillary_sphere_model.jpg/500px-Ptolemy_1476_with_armillary_sphere_model.jpg','#8b5cf6',5,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(6,'physicist','Папп Александрийский',290,350,'Александрийский математик и механик. В «Математическом собрании» систематизировал достижения древнегреческой геометрии и механики, ввёл понятия центра тяжести и теоремы, лёгшие в основу проективной геометрии.','https://upload.wikimedia.org/wikipedia/commons/thumb/d/de/Pappus_-_Mathematicae_collectiones%2C_1660.jpg/500px-Pappus_-_Mathematicae_collectiones%2C_1660.jpg','#ec4899',6,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(7,'physicist','Гипатия',360,415,'Александрийский философ, математик и астроном. Одна из первых женщин-учёных в истории. Составляла комментарии к трудам по математике и астрономии, конструировала астрономические инструменты и преподавала в Александрийской школе.','https://upload.wikimedia.org/wikipedia/commons/thumb/0/07/Hypatia_portrait.png/500px-Hypatia_portrait.png','#f472b6',7,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(8,'physicist','Ариабхата',476,550,'Индийский математик и астроном. Первым предположил, что Земля вращается вокруг своей оси, объяснил причины затмений и ввёл важные математические понятия, включая использование нуля и десятичной системы.','https://upload.wikimedia.org/wikipedia/commons/thumb/a/af/2064_aryabhata-crp.jpg/500px-2064_aryabhata-crp.jpg','#3b82f6',8,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(9,'discovery','Вращение Земли вокруг оси',500,NULL,'Ариабхата в своём труде «Ариабхатия» (около 500 года) предположил, что Земля вращается вокруг своей оси, объяснил смену дня и ночи и дал первые научные объяснения лунных и солнечных затмений.','https://upload.wikimedia.org/wikipedia/commons/thumb/a/af/2064_aryabhata-crp.jpg/500px-2064_aryabhata-crp.jpg','#3b82f6',9,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(10,'physicist','Брахмагупта',598,668,'Индийский математик и астроном. Сформулировал правила арифметических операций с нулём и отрицательными числами, развил тригонометрию и астрономию, изучал гравитацию и движение планет.','https://upload.wikimedia.org/wikipedia/commons/thumb/b/ba/Bas-relief_of_Brahmagupta.jpg/500px-Bas-relief_of_Brahmagupta.jpg','#f43f5e',10,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(11,'physicist','Аль-Хорезми',780,850,'Персидский математик, астроном и географ. Считается «отцом алгебры» благодаря систематизации решения уравнений. Его работы по арифметике способствовали распространению десятичной системы счисления.','https://upload.wikimedia.org/wikipedia/commons/d/dd/Al-Khwarizmi_portrait.jpg','#10b981',11,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(12,'physicist','Аль-Фаргани',805,880,'Арабский астроном и инженер. Составил «Книгу о движении небесных тел», которая вошла в средневековую Европу как основной астрономический учебник. Участвовал в строительстве Нилометра в Каире.','https://upload.wikimedia.org/wikipedia/commons/thumb/7/72/Statue_of_Al-Farghani_in_Fergana.jpg/500px-Statue_of_Al-Farghani_in_Fergana.jpg','#06b6d4',12,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(13,'discovery','Основы алгебры',820,NULL,'Аль-Хорезми в труде «Краткая книга об исчислении алгебры и альмукабалы» систематизировал решение линейных и квадратных уравнений. От его имени произошло слово «алгоритм», а от названия книги — «алгебра».','https://upload.wikimedia.org/wikipedia/commons/d/dd/Al-Khwarizmi_portrait.jpg','#10b981',13,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(14,'physicist','Аль-Баттани',858,929,'Арабский астроном и математик. Уточнил длительность солнечного года, измерил наклон эклиптики, составил точные астрономические таблицы. Его работы легли в основу европейской астрономии эпохи Возрождения.','https://upload.wikimedia.org/wikipedia/commons/e/ed/Albategnius.jpeg','#84cc16',14,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(15,'physicist','Ибн аль-Хайсам',965,1040,'Арабский физик, математик и астроном, известный как «отец оптики». Экспериментально исследовал преломление и отражение света, описал работу камеры-обскуры и впервые объяснил механизм зрения.','https://upload.wikimedia.org/wikipedia/commons/9/90/Ibn_al-Haytham.jpg','#eab308',15,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(16,'physicist','Абу Райхан Бируни',973,1048,'Персидский учёный-энциклопедист, физик, астроном и геодезист. Провёл первые научные измерения радиуса Земли, изучил плотность веществ, затмения и вращение Земли. Считается одним из крупнейших учёных средневековья.','https://upload.wikimedia.org/wikipedia/commons/thumb/b/b9/Al-Biruni.jpg/500px-Al-Biruni.jpg','#a855f7',16,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(17,'discovery','Книга об оптике',1021,NULL,'Ибн аль-Хайсам написал семитомный труд «Книга об оптике», в котором экспериментально доказал, что свет распространяется прямолинейно, исследовал преломление и отражение, описал работу камеры-обскуры и объяснил механизм зрения.','https://upload.wikimedia.org/wikipedia/commons/9/90/Ibn_al-Haytham.jpg','#eab308',17,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(18,'physicist','Аль-Заркали',1028,1087,'Андалузский астроном и инструментальщик. Создал точные астрономические таблицы, усовершенствовал астролябию и развил теорию движения планет. Его работы были широко известны в средневековой Европе.','https://upload.wikimedia.org/wikipedia/commons/thumb/4/43/Azarquiel_%28MUNCYT%2C_Eulogia_Merle%29.jpg/500px-Azarquiel_%28MUNCYT%2C_Eulogia_Merle%29.jpg','#14b8a6',18,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(19,'physicist','Омар Хайям',1048,1131,'Персидский математик, астроном и поэт. Руководил реформой календаря, составил точные астрономические таблицы, внёс важный вклад в алгебру и теорию параллельных прямых.','https://upload.wikimedia.org/wikipedia/commons/thumb/d/da/Omar_Khayyam2.JPG/500px-Omar_Khayyam2.JPG','#f97316',19,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(20,'physicist','Моисей Маймонид',1135,1204,'Испанский философ, врач и учёный. Автор медицинских трактатов, в которых систематизировал знания о болезнях и лечении. Его работы оказали большое влияние на развитие медицины и естественных наук.','https://upload.wikimedia.org/wikipedia/commons/thumb/2/2a/Maim%C3%B2nides.jpg/500px-Maim%C3%B2nides.jpg','#84cc16',20,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(21,'physicist','Насир ад-Дин ат-Туси',1201,1274,'Персидский астроном, математик и философ. Создал «Зидж-и Илхани» — точные астрономические таблицы, развил тригонометрию как самостоятельную науку, построил обсерваторию в Мараге.','https://upload.wikimedia.org/wikipedia/commons/thumb/7/75/Nasir_al-Din_Tusi.jpg/500px-Nasir_al-Din_Tusi.jpg','#8b5cf6',21,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(22,'physicist','Ибн аль-Шатир',1304,1375,'Дамаскский астроном и часовщик. Создал точные модели движения Луны и планет, независимо открывший идеи, близкие к работам Коперника. Усовершенствовал астрономические инструменты.','https://upload.wikimedia.org/wikipedia/commons/c/c4/Ibn-al-shatir2.gif','#ec4899',22,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(23,'physicist','Улугбек',1394,1449,'Тимуридский правитель, астроном и математик. Основал обсерваторию в Самарканде, где были составлены «Зидж-и Джадид-и Гургани» — одни из самых точных астрономических таблиц того времени.','https://upload.wikimedia.org/wikipedia/commons/thumb/4/45/Ulugh_Beg_Observatory_Museum_02.jpg/500px-Ulugh_Beg_Observatory_Museum_02.jpg','#06b6d4',23,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(24,'physicist','Николай Кузанский',1401,1464,'Немецкий философ, математик и кардинал. Выдвинул идею о бесконечности Вселенной и относительности движения, предвосхитив гелиоцентрическую картину мира. Изучал математику бесконечного.','https://upload.wikimedia.org/wikipedia/commons/thumb/4/4c/Nicholas_of_Cusa.jpg/500px-Nicholas_of_Cusa.jpg','#d946ef',24,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(25,'discovery','Самаркандская обсерватория',1420,NULL,'Улугбек построил в Самарканде одну из крупнейших обсерваторий средневековья. С её помощью астрономы получили высокоточные измерения положений звёзд и планет.','https://upload.wikimedia.org/wikipedia/commons/thumb/4/45/Ulugh_Beg_Observatory_Museum_02.jpg/500px-Ulugh_Beg_Observatory_Museum_02.jpg','#06b6d4',25,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(26,'physicist','Региомонтан',1436,1476,'Немецкий астроном и математик. Возродил европейскую тригонометрию, составил точные эфемериды и таблицы, подготовил издание «Альмагеста», заложив основы современной астрономии.','https://upload.wikimedia.org/wikipedia/commons/thumb/b/b8/Johannes_Regiomontanus.jpg/500px-Johannes_Regiomontanus.jpg','#f43f5e',26,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(27,'physicist','Николай Коперник',1473,1543,'Польский астроном, математик и каноник. Создал гелиоцентрическую систему мира, в которой Солнце, а не Земля, находится в центре. Его труд «О вращении небесных сфер» (1543) стал одним из важнейших этапов научной революции.','https://upload.wikimedia.org/wikipedia/commons/thumb/f/f2/Nikolaus_Kopernikus.jpg/500px-Nikolaus_Kopernikus.jpg','#a78bfa',27,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(28,'discovery','Гелиоцентрическая система мира',1543,NULL,'В 1543 году Николай Коперник опубликовал работу «О вращении небесных сфер», в которой поместил Солнце в центр мира. Это положило начало научной революции и радикально изменило представления о месте Земли во Вселенной.','https://upload.wikimedia.org/wikipedia/commons/thumb/f/f2/Nikolaus_Kopernikus.jpg/500px-Nikolaus_Kopernikus.jpg','#a78bfa',28,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(29,'physicist','Вильям Гильберт',1544,1603,'Английский врач и физик, основоположник научного учения о магнетизме. В 1600 году опубликовал труд «О магните, магнитных телах и о большом магните — Земле», где показал, что Земля ведёт себя как гигантский магнит.','https://upload.wikimedia.org/wikipedia/commons/8/87/William_Gilbert.jpg','#8b5cf6',29,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(30,'physicist','Галилео Галилей',1564,1642,'Итальянский физик, астроном и математик, основоположник экспериментального метода в физике. Создал первый телескоп, открыл спутники Юпитера, фазы Венеры, горы на Луне и солнечные пятна. Сформулировал закон инерции и закон свободного падения.','https://upload.wikimedia.org/wikipedia/commons/thumb/d/d4/Justus_Sustermans_-_Portrait_of_Galileo_Galilei%2C_1636.jpg/500px-Justus_Sustermans_-_Portrait_of_Galileo_Galilei%2C_1636.jpg','#87CEEB',30,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(31,'physicist','Иоганн Кеплер',1571,1630,'Немецкий математик, астроном и оптик. Открыл три закона движения планет, заложивших основу небесной механики. Его работы позволили Ньютону сформулировать закон всемирного тяготения.','https://upload.wikimedia.org/wikipedia/commons/thumb/d/d5/Johannes_Kepler.jpg/500px-Johannes_Kepler.jpg','#06b6d4',31,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(32,'discovery','Магнетизм Земли',1600,NULL,'Вильям Гильберт в 1600 году показал, что Земля ведёт себя как гигантский магнит, а магнитное притяжение зависит от природы тела, а не от его движения. Его работа стала первым научным исследованием магнетизма.','https://upload.wikimedia.org/wikipedia/commons/8/87/William_Gilbert.jpg','#8b5cf6',32,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(33,'discovery','Законы Кеплера',1609,NULL,'Иоганн Кеплер открыл три закона движения планет: орбиты эллиптичны, радиус-вектор заметает равные площади за равные промежутки времени, период обращения связан с размером орбиты. Эти законы легли в основу небесной механики.','https://upload.wikimedia.org/wikipedia/commons/thumb/d/d5/Johannes_Kepler.jpg/500px-Johannes_Kepler.jpg','#06b6d4',33,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(34,'discovery','Телескоп Галилея',1609,NULL,'В 1609 году Галилей собрал свой первый телескоп и направил его на небо. Он открыл горы на Луне, четыре крупнейших спутника Юпитера, фазы Венеры и многочисленные звёзды Млечного Пути — революционные доказательства в пользу гелиоцентрической системы мира.','https://upload.wikimedia.org/wikipedia/commons/thumb/d/d4/Justus_Sustermans_-_Portrait_of_Galileo_Galilei%2C_1636.jpg/500px-Justus_Sustermans_-_Portrait_of_Galileo_Galilei%2C_1636.jpg','#87CEEB',34,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(35,'physicist','Блез Паскаль',1623,1662,'Французский математик, физик и философ. Сформулировал закон равновесия жидкостей и газов, изучил атмосферное давление, создал первые образцы гидравлического пресса и счётной машины.','https://upload.wikimedia.org/wikipedia/commons/thumb/c/c1/Blaise_Pascal_2.jpg/500px-Blaise_Pascal_2.jpg','#14b8a6',35,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(36,'physicist','Роберт Бойль',1627,1691,'Английский физик и химик, один из основателей современной химии. Сформулировал закон, связывающий давление и объём газа при постоянной температуре. Исследовал свойства воздуха, вакуума и эластичности.','https://upload.wikimedia.org/wikipedia/commons/thumb/b/b3/Robert_Boyle_0001.jpg/500px-Robert_Boyle_0001.jpg','#84cc16',36,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(37,'physicist','Христиан Гюйгенс',1629,1695,'Голландский физик, математик и астроном. Создал волновую теорию света, изобрёл маятниковые часы, открыл спутник Сатурна — Титан, исследовал центробежную силу и столкновения тел.','https://upload.wikimedia.org/wikipedia/commons/thumb/a/a4/Christiaan_Huygens-painting.jpeg/500px-Christiaan_Huygens-painting.jpeg','#0ea5e9',37,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(38,'physicist','Исаак Ньютон',1643,1727,'Английский физик, математик и астроном. Сформулировал законы движения и универсального тяготения, развил исчисление, создал первый зеркальный телескоп. Его «Математические начала натуральной философии» (1687) стали фундаментом классической механики.','https://upload.wikimedia.org/wikipedia/commons/thumb/3/3b/Portrait_of_Sir_Isaac_Newton%2C_1689.jpg/500px-Portrait_of_Sir_Isaac_Newton%2C_1689.jpg','#87CEEB',38,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(39,'discovery','Закон Паскаля',1653,NULL,'Блез Паскаль сформулировал закон передачи давления в жидкости и газе: давление, приложенное к поверхности жидкости, передаётся одинаково во все стороны. Этот принцип лёг в основу гидравлических механизмов.','https://upload.wikimedia.org/wikipedia/commons/thumb/c/c1/Blaise_Pascal_2.jpg/500px-Blaise_Pascal_2.jpg','#14b8a6',39,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(40,'discovery','Закон Бойля-Мариотта',1662,NULL,'Роберт Бойль установил, что при постоянной температуре произведение давления и объёма газа остаётся постоянным. Этот закон стал одним из первых количественных соотношений в физике газов.','https://upload.wikimedia.org/wikipedia/commons/thumb/b/b3/Robert_Boyle_0001.jpg/500px-Robert_Boyle_0001.jpg','#84cc16',40,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(41,'discovery','Волновая теория света',1678,NULL,'Христиан Гюйгенс предложил волновую теорию света, согласно которой свет распространяется в виде волн в эфире. Его идеи объяснили законы отражения, преломления и двойного лучепреломления.','https://upload.wikimedia.org/wikipedia/commons/thumb/a/a4/Christiaan_Huygens-painting.jpeg/500px-Christiaan_Huygens-painting.jpeg','#0ea5e9',41,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(42,'discovery','«Математические начала натуральной философии»',1687,NULL,'Книга Исаака Ньютона, в которой изложены три закона движения и закон всемирного тяготения. Этот труд объединил земную и небесную механику и стал основой физики на следующие два с половиной века.','https://upload.wikimedia.org/wikipedia/commons/thumb/3/3b/Portrait_of_Sir_Isaac_Newton%2C_1689.jpg/500px-Portrait_of_Sir_Isaac_Newton%2C_1689.jpg','#87CEEB',42,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(43,'physicist','Бенджамин Франклин',1706,1790,'Американский политический деятель, изобретатель и учёный. Проводил опыты с электричеством, доказал грозовую природу молнии, ввёл понятия положительного и отрицательного заряда, изобрёл молниеотвод.','https://upload.wikimedia.org/wikipedia/commons/thumb/c/cc/BenFranklinDuplessis.jpg/500px-BenFranklinDuplessis.jpg','#eab308',43,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(44,'physicist','Леонард Эйлер',1707,1783,'Швейцарский и российский математик, механик и физик. Внёс огромный вклад в механику, гидродинамику, оптику и астрономию. Его работы по аналитической механике легли в основу современной физики.','https://upload.wikimedia.org/wikipedia/commons/thumb/f/f9/Leonhard_Euler_-_Jakob_Emanuel_Handmann_%28Kunstmuseum_Basel%29.jpg/500px-Leonhard_Euler_-_Jakob_Emanuel_Handmann_%28Kunstmuseum_Basel%29.jpg','#f43f5e',44,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(45,'physicist','Михаил Ломоносов',1711,1765,'Русский учёный-естествоиспытатель, химик и физик. Сформулировал закон сохранения массы вещества в химических реакциях, заложил основы физической химии, изучал атмосферное электричество и тепловые явления.','https://upload.wikimedia.org/wikipedia/commons/7/70/Mikhail_Lomonosov.jpg','#01acff',45,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(46,'discovery','Закон сохранения массы вещества',1748,NULL,'В 1748 году Михаил Ломоносов сформулировал фундаментальный закон: масса веществ, участвующих в химической реакции, остаётся неизменной. Этот закон лёг в основу стехиометрии и химической термодинамики.','https://upload.wikimedia.org/wikipedia/commons/7/70/Mikhail_Lomonosov.jpg','#01acff',46,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(47,'discovery','Молния как электричество',1752,NULL,'Бенджамин Франклин в 1752 году провёл знаменитый опыт с воздушным змеем и доказал, что молния — это разряд статического электричества. Это открытие привело к изобретению молниеотвода.','https://upload.wikimedia.org/wikipedia/commons/thumb/c/cc/BenFranklinDuplessis.jpg/500px-BenFranklinDuplessis.jpg','#eab308',47,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(48,'physicist','Андре-Мари Ампер',1775,1836,'Французский физик и математик, основоположник электродинамики. Сформулировал закон силы, действующей между проводниками с током, и ввёл понятие электрического тока как физической величины.','https://upload.wikimedia.org/wikipedia/commons/4/4f/Andre-Marie_Ampere.jpg','#d946ef',48,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(49,'physicist','Майкл Фарадей',1791,1867,'Английский физик и химик, один из основоположников электродинамики. Открыл явление электромагнитной индукции, ввёл понятия магнитного поля и силовых линий, создал первые электродвигатели и генераторы.','https://upload.wikimedia.org/wikipedia/commons/thumb/5/5b/Faraday-Millikan-Gale-1913.jpg/500px-Faraday-Millikan-Gale-1913.jpg','#22c55e',49,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(50,'discovery','Закон Ампера',1820,NULL,'В 1820 году Андре-Мари Ампер установил закон взаимодействия проводников с электрическим током и заложил основы электродинамики. Он также ввёл понятие электрического тока как направленного движения зарядов.','https://upload.wikimedia.org/wikipedia/commons/4/4f/Andre-Marie_Ampere.jpg','#d946ef',50,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(51,'physicist','Джеймс Клерк Максвелл',1831,1879,'Шотландский физик, создатель классической электродинамики. Система уравнений Максвелла описывает электромагнитное поле и предсказала существование электромагнитных волн, распространяющихся со скоростью света.','https://upload.wikimedia.org/wikipedia/commons/4/42/James_Clerk_Maxwell.jpg','#22c55e',51,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(52,'discovery','Электромагнитная индукция',1831,NULL,'В 1831 году Майкл Фарадей открыл явление электромагнитной индукции: изменение магнитного потока в проводящем контуре порождает электрический ток. Это открытие привело к созданию генераторов и трансформаторов.','https://upload.wikimedia.org/wikipedia/commons/thumb/5/5b/Faraday-Millikan-Gale-1913.jpg/500px-Faraday-Millikan-Gale-1913.jpg','#22c55e',52,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(53,'discovery','Уравнения Максвелла',1865,NULL,'Джеймс Клерк Максвелл объединил электричество, магнетизм и оптику в единую теорию электромагнитного поля. Его уравнения предсказали электромагнитные волны и показали, что свет — это электромагнитная волна.','https://upload.wikimedia.org/wikipedia/commons/4/42/James_Clerk_Maxwell.jpg','#22c55e',53,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(54,'physicist','Мария Склодовская-Кюри',1867,1934,'Польско-французский физик и химик, пионер исследований радиоактивности. Дважды лауреат Нобелевской премии: по физике (1903, совместно с Пьером Кюри и Анри Беккерелем) и по химии (1911). Открыла элементы полоний и радий.','https://upload.wikimedia.org/wikipedia/commons/thumb/7/7e/Marie_Curie_c1920.jpg/500px-Marie_Curie_c1920.jpg','#a855f7',54,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(55,'physicist','Эрнест Резерфорд',1871,1937,'Новозеландский и британский физик, основоположник ядерной физики. В 1911 году предложил планетарную модель атома с положительно заряженным ядром. Лауреат Нобелевской премии по химии (1908) за исследования распада элементов.','https://upload.wikimedia.org/wikipedia/commons/thumb/d/de/Ernest_Rutherford_1908.jpg/500px-Ernest_Rutherford_1908.jpg','#f97316',55,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(56,'physicist','Альберт Эйнштейн',1879,1955,'Немецкий физик-теоретик, автор специальной и общей теорий относительности. В 1905 году объяснил фотоэффект, ввёл понятие кванта света и получил Нобелевскую премию по физике (1921). Его знаменитая формула E = mc² связала массу и энергию.','https://upload.wikimedia.org/wikipedia/commons/thumb/3/3e/Einstein_1921_by_F_Schmutzer_-_restoration.jpg/500px-Einstein_1921_by_F_Schmutzer_-_restoration.jpg','#f97316',56,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(57,'physicist','Нильс Бор',1885,1962,'Датский физик-теоретик, основоположник квантовой теории атома. В 1913 году предложил модель атома, в которой электроны движутся по стационарным орбитам и излучают энергию при переходах между ними. Лауреат Нобелевской премии по физике (1922).','https://upload.wikimedia.org/wikipedia/commons/thumb/6/6d/Niels_Bohr.jpg/500px-Niels_Bohr.jpg','#ec4899',57,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(58,'discovery','Рентгеновские лучи',1895,NULL,'Вильгельм Рентген открыл X-лучи — проникающее излучение, способное проходить через мягкие ткани человека. Открытие произвело революцию в медицине и физике и принесло Рентгену первую Нобелевскую премию по физике (1901).','https://upload.wikimedia.org/wikipedia/commons/4/48/Wilhelm_R%C3%B6ntgen.jpg','#a855f7',58,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(59,'discovery','Специальная теория относительности',1905,NULL,'В 1905 году Альберт Эйнштейн опубликовал работу «К электродинамике движущихся тел», положившую начало СТО. Она пересмотрела понятия пространства и времени, ввела постулат постоянства скорости света и привела к знаменитой формуле E = mc².','https://upload.wikimedia.org/wikipedia/commons/thumb/3/3e/Einstein_1921_by_F_Schmutzer_-_restoration.jpg/500px-Einstein_1921_by_F_Schmutzer_-_restoration.jpg','#f97316',59,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(60,'discovery','Фотоэффект',1905,NULL,'Эйнштейн объяснил фотоэффект, предположив, что свет состоит из квантов (фотонов). Работа положила начало квантовой теории и была отмечена Нобелевской премией 1921 года. Уравнение hν = A + Ek связывает энергию фотона с работой выхода и кинетической энергией электрона.','https://upload.wikimedia.org/wikipedia/commons/thumb/3/3e/Einstein_1921_by_F_Schmutzer_-_restoration.jpg/500px-Einstein_1921_by_F_Schmutzer_-_restoration.jpg','#f97316',60,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(61,'discovery','Планетарная модель атома',1911,NULL,'В 1911 году Эрнест Резерфорд на основе опытов по рассеянию α-частиц предложил модель атома, в котором почти вся масса и положительный заряд сосредоточены в крошечном ядре, а электроны обращаются вокруг него.','https://upload.wikimedia.org/wikipedia/commons/thumb/d/de/Ernest_Rutherford_1908.jpg/500px-Ernest_Rutherford_1908.jpg','#f97316',61,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(62,'discovery','Квантовая модель атома Бора',1913,NULL,'В 1913 году Нильс Бор предложил модель атома, в которой электроны могут находиться только на определённых стационарных орбитах. При переходе между ними атом излучает или поглощает кванты света с энергией hν.','https://upload.wikimedia.org/wikipedia/commons/thumb/6/6d/Niels_Bohr.jpg/500px-Niels_Bohr.jpg','#ec4899',62,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(63,'physicist','Ричард Фейнман',1918,1988,'Американский физик-теоретик, один из основателей квантовой электродинамики. Лауреат Нобелевской премии (1965). Известен диаграммами Фейнмана, интегралом по траекториям и ясным стилем преподавания физики.','https://upload.wikimedia.org/wikipedia/commons/thumb/0/06/Richard_Feynman_1959.png/500px-Richard_Feynman_1959.png','#fdba74',63,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(64,'discovery','Квантовая механика',1925,NULL,'В 1920-е годы Шрёдингер, Гейзенберг, Борн, Дирак и другие создали квантовую механику — фундаментальную теорию поведения микрочастиц. Были введены волновая функция, принцип неопределённости и матричная механика.','https://upload.wikimedia.org/wikipedia/commons/2/2e/Erwin_Schr%C3%B6dinger_%281933%29.jpg','#a855f7',64,'2026-06-19 14:13:39','2026-06-19 14:13:39'),(65,'discovery','Бозон Хиггса',2012,NULL,'4 июля 2012 года коллаборации ATLAS и CMS на Большом адронном коллайдере объявили об открытии новой элементарной частицы — бозона Хиггса. Его существование подтвердило механизм придания массы другим частицам и завершило Стандартную модель.','https://upload.wikimedia.org/wikipedia/commons/thumb/1/1c/CMS_Higgs-event.jpg/500px-CMS_Higgs-event.jpg','#fbbf24',65,'2026-06-19 14:13:39','2026-06-19 14:13:39');
